var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// FIX (Breaking Change 1 — ValidateScopes): Scoped IUserService was captured
// inside a singleton, which now throws in development because .NET 9 enables
// ValidateScopes by default. Changed ICacheService to Scoped to match.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// FIX (Breaking Change 2 — SocketsHttpHandler): In .NET 9 the default primary
// handler is SocketsHttpHandler, so casting to HttpClientHandler throws
// InvalidCastException. Use ConfigurePrimaryHttpMessageHandler instead.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// FIX (Breaking Change 3 — Header redaction): .NET 9 redacts all header values
// in Trace-level HttpClientFactory logs by default. Allowlist specific
// non-sensitive headers so they remain visible for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Cache-Control"
        && h != "Accept"
        && h != "Content-Type"));

// FIX (Breaking Change 4 — Forwarded Headers): .NET 9 ignores X-Forwarded-*
// headers from proxies not listed in KnownProxies or KnownNetworks.
// Add your reverse-proxy address/network here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual proxy address or network range
    options.KnownProxies.Add(System.Net.IPAddress.Parse("10.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

